import React, { useState, useEffect, useRef, useCallback } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { chaptersAPI, progressAPI } from '../services/api';
import VirtualKeyboard from '../components/VirtualKeyboard';
import { useLanguage } from '../contexts/LanguageContext';
import './Lesson.css';

// ── Punjabi Inscript map: e.key → Gurmukhi character ────────────────────────
const INSCRIPT_MAP = {
  'q':'ੌ','w':'ੈ','e':'ਾ','r':'ੀ','t':'ੂ',
  'y':'ਬ','u':'ਹ','i':'ਗ','o':'ਦ','p':'ਜ',
  '[':'ਡ',']':'਼',
  'a':'ੋ','s':'ੇ','d':'੍','f':'ਿ','g':'ੁ',
  'h':'ਪ','j':'ਰ','k':'ਕ','l':'ਤ',';':'ਚ',"'":'ਟ',
  'z':'ੱ','x':'ਂ','c':'ਮ','v':'ਨ','b':'ਵ',
  'n':'ਲ','m':'ਸ',',':',','.':'.','/':'ਯ',' ':' ',
  // Shift layer
  'Q':'ਔ','W':'ਐ','E':'ਆ','R':'ਈ','T':'ਊ',
  'Y':'ਭ','U':'ਙ','I':'ਘ','O':'ਧ','P':'ਝ',
  '{':'ਢ','}':'ਞ',
  'A':'ਓ','S':'ਏ','D':'ਅ','F':'ਇ','G':'ਉ',
  'H':'ਫ','J':'ੜ','K':'ਖ','L':'ਥ',':':'ਛ','"':'ਠ',
  'Z':'ਃ','X':'ਁ','C':'ਣ','V':'ੲ','B':'ੳ',
  'N':'ਲ਼','M':'ਸ਼','>':'।',
};

// ── Lesson types that use blocking (wrong key = red, nothing typed) ──────────
const BLOCKING_TYPES = ['intro', 'random-words', 'meaningful-words'];

// Split full content into lines/chunks
const splitIntoLines = (text, lessonType) => {
  if (lessonType === 'paragraph') {
    console.log('🔄 Paragraph mode: splitting into 5-sentence chunks...');
    const sentences = text
      .split(/(?<=[.!?])\s+/)
      .map(s => s.trim())
      .filter(Boolean);
    console.log(`📝 Found ${sentences.length} sentences in paragraph`);
    const chunks = [];
    const SENTENCES_PER_CHUNK = 5;
    for (let i = 0; i < sentences.length; i += SENTENCES_PER_CHUNK) {
      const chunk = sentences.slice(i, i + SENTENCES_PER_CHUNK).join(' ');
      chunks.push(chunk);
    }
    console.log(`📦 Created ${chunks.length} chunks of ${SENTENCES_PER_CHUNK} sentences each`);
    return chunks.length > 0 ? chunks : [text];
  }

  if (lessonType === 'sentences') {
    const sentences = text
      .split(/(?<=[.!?])\s+/)
      .map(s => s.trim())
      .filter(Boolean);
    return sentences.length > 0 ? sentences : [text];
  }

  // intro / random-words / meaningful-words → 10-word chunks
  const words = text.trim().split(/\s+/);
  const chunks = [];
  const PER_LINE = 10;
  for (let i = 0; i < words.length; i += PER_LINE) {
    chunks.push(words.slice(i, i + PER_LINE).join(' '));
  }
  return chunks;
};

const Lesson = () => {
  const { chapterId, lessonId } = useParams();
  const navigate = useNavigate();
  const { language } = useLanguage();

  const [lessonData, setLessonData]   = useState(null);
  const [loading, setLoading]         = useState(true);
  const [error, setError]             = useState(null);

  // Line-by-line state
  const [lines, setLines]             = useState([]);
  const [lineIndex, setLineIndex]     = useState(0);
  const [charIndex, setCharIndex]     = useState(0);
  const [wrongChar, setWrongChar]     = useState(false);
  const [linePhase, setLinePhase]     = useState('visible'); // 'visible' | 'fadeout' | 'fadein'

  // Global stats
  const [totalChars, setTotalChars]   = useState(0);
  const [errors, setErrors]           = useState(0);
  const [userInput, setUserInput]     = useState('');

  // Timer
  const [timeElapsed, setTimeElapsed] = useState(0);

  // Completion
  const [isComplete, setIsComplete]   = useState(false);
  const [showResults, setShowResults] = useState(false);

  // Sound feedback
  const [lastKeyCorrect, setLastKeyCorrect] = useState(null);

  const inputRef    = useRef(null);
  const timerRef    = useRef(null);
  const startRef    = useRef(null);
  const errorsRef   = useRef(0);
  const charsRef    = useRef(0);
  const lineIdxRef  = useRef(0);   // always-current lineIndex for use inside setTimeout
  const linesRef    = useRef([]);  // always-current lines array for use inside setTimeout

  // ─── Load lesson ────────────────────────────────────────
  useEffect(() => {
    const fetchLesson = async () => {
      try {
        const res = await chaptersAPI.getLesson(chapterId, lessonId);
        const data = res.data;
        setLessonData(data);
        const ls = splitIntoLines(data.lesson.content, data.lesson.lessonType);
        setLines(ls);
        linesRef.current = ls;
      } catch {
        setError('Failed to load lesson');
      } finally {
        setLoading(false);
      }
    };
    fetchLesson();
    return () => clearInterval(timerRef.current);
  }, [chapterId, lessonId]);

  // Keep lineIdxRef in sync with lineIndex state
  useEffect(() => {
    lineIdxRef.current = lineIndex;
  }, [lineIndex]);

  useEffect(() => {
    if (!isComplete && inputRef.current) inputRef.current.focus();
  }, [isComplete, lineIndex]);

  // ─── Timer ───────────────────────────────────────────────
  const startTimer = () => {
    if (startRef.current) return;
    startRef.current = Date.now();
    timerRef.current = setInterval(() => {
      setTimeElapsed(Math.floor((Date.now() - startRef.current) / 1000));
    }, 500);
  };

  // ─── Live WPM ────────────────────────────────────────────
  const calcWpm = () => {
    if (!startRef.current || charsRef.current === 0) return 0;
    const mins = (Date.now() - startRef.current) / 60000;
    if (mins < 0.01) return 0;
    return Math.round((charsRef.current / 5) / mins);
  };

  // ─── Submit ───────────────────────────────────────────────
  const handleSubmit = useCallback(async () => {
    clearInterval(timerRef.current);
    const elapsed = startRef.current ? Math.round((Date.now() - startRef.current) / 1000) : 0;
    setTimeElapsed(elapsed);

    const mins = elapsed / 60 || 0.1;
    const wpm = Math.round((charsRef.current / 5) / mins);
    const totalLen = lines.join(' ').length || 1;
    const accuracy = Math.max(0, Math.round(((totalLen - errorsRef.current) / totalLen) * 100));

    try {
      await progressAPI.submitLesson({ chapterId, lessonId, wpm, accuracy });
    } catch (e) {
      console.error('Submit failed', e);
    }
    setIsComplete(true);
    setShowResults(true);
  }, [chapterId, lessonId, lines]);

  // ─── Line transition ──────────────────────────────────────
  const advanceToNextLine = useCallback(() => {
    setLinePhase('fadeout');
    setTimeout(() => {
      // Use refs so we always read the latest values — never stale inside setTimeout
      const next = lineIdxRef.current + 1;
      if (next >= linesRef.current.length) {
        handleSubmit();
        return;
      }
      lineIdxRef.current = next;
      setLineIndex(next);
      setCharIndex(0);
      setUserInput('');
      setWrongChar(false);
      setLinePhase('fadein');
      setTimeout(() => setLinePhase('visible'), 250);
    }, 280);
  }, [handleSubmit]);

  // ─── Typing handler (English non-blocking and paragraph only) ────────────
  const handleInputChange = (e) => {
    if (linePhase !== 'visible' || isComplete) return;
    if (language === 'punjabi') return; // Punjabi fully handled by keyDown
    if (BLOCKING_TYPES.includes(lessonData?.lesson?.lessonType)) return; // blocking types handled by keyDown

    const value = e.target.value;
    const currentLine = lines[lineIndex] || '';
    const isDeleting = value.length < userInput.length;
    const isParagraph = lessonData?.lesson?.lessonType === 'paragraph';

    if (!startRef.current) startTimer();

    // PARAGRAPH MODE: Free typing
    if (isParagraph) {
      setUserInput(value);
      return;
    }

    // DELETING (backspace) — sentences only reaches here
    if (isDeleting) {
      setUserInput(value);
      if (!wrongChar) setCharIndex(prev => Math.max(0, prev - 1));
      setWrongChar(false);
      setLastKeyCorrect(null);
      return;
    }

    // Wrong char shown — block until backspace clears it
    if (wrongChar) return;

    // Use charIndex as the canonical position — compare the char at that position
    // in the new value against what's expected. This is reliable even if value
    // length drifts (e.g. paste, autocorrect) because charIndex is our ground truth.
    const typedChar    = value[charIndex];
    const expectedChar = currentLine[charIndex];

    // If the new value doesn't yet have a char at charIndex, ignore (e.g. deletion edge case)
    if (typedChar === undefined) return;

    if (typedChar !== expectedChar) {
      errorsRef.current += 1;
      setErrors(errorsRef.current);
      setWrongChar(true);
      setLastKeyCorrect(false);
      setUserInput(value);
      return;
    }

    setWrongChar(false);
    setLastKeyCorrect(true);
    setUserInput(value);
    charsRef.current += 1;
    setTotalChars(charsRef.current);
    const newCharIndex = charIndex + 1;
    setCharIndex(newCharIndex);
    if (newCharIndex >= currentLine.length) advanceToNextLine();
  };

  // ─── Key handler ──────────────────────────────────────────────────────────
  const handleKeyDown = (e) => {
    const lessonType  = lessonData?.lesson?.lessonType;
    const isParagraph = lessonType === 'paragraph';
    const isPunjabi   = language === 'punjabi';
    const isBlocking  = BLOCKING_TYPES.includes(lessonType);

    // ── PUNJABI: intercept all keys ────────────────────────────────────────
    if (isPunjabi) {
      if (e.ctrlKey || e.metaKey || e.altKey) return;
      if (e.key.length > 1 && e.key !== 'Backspace' && e.key !== 'Enter') return;

      // Backspace
      if (e.key === 'Backspace') {
        e.preventDefault();
        if (linePhase !== 'visible' || isComplete) return;
        // Block backspace entirely for blocking lesson types
        if (!isParagraph && isBlocking) return;
        setUserInput(prev => prev.slice(0, -1));
        if (!isParagraph) {
          if (!wrongChar) setCharIndex(prev => Math.max(0, prev - 1));
        }
        setWrongChar(false);
        setLastKeyCorrect(null);
        return;
      }

      // Enter — paragraph mode only
      if (e.key === 'Enter') {
        if (!isParagraph || linePhase !== 'visible') return;
        e.preventDefault();
        if (!userInput.trim()) return;
        const currentLine = lines[lineIndex] || '';
        const typed  = userInput.trim();
        const target = currentLine.replace(/\s+$/, '');
        let chunkErrors = 0;
        const maxLen = Math.max(typed.length, target.length);
        for (let i = 0; i < maxLen; i++) {
          if (typed[i] !== target[i]) chunkErrors++;
        }
        errorsRef.current += chunkErrors;
        setErrors(errorsRef.current);
        charsRef.current += currentLine.length;
        setTotalChars(charsRef.current);
        advanceToNextLine();
        return;
      }

      // Printable key — map through Inscript table
      e.preventDefault();
      if (linePhase !== 'visible' || isComplete) return;

      const mapped = INSCRIPT_MAP[e.key];
      if (!mapped) return;

      if (!startRef.current) startTimer();

      // Paragraph: free type
      if (isParagraph) {
        setUserInput(prev => prev + mapped);
        return;
      }

      // ── BLOCKING mode (intro / random-words / meaningful-words) ───────────
      if (isBlocking) {
        const currentLine  = lines[lineIndex] || '';
        const expectedChar = currentLine[charIndex];

        if (wrongChar) {
          // Only the correct key clears the error and advances
          if (mapped === expectedChar) {
            setWrongChar(false);
            setLastKeyCorrect(true);
            setUserInput(prev => prev + mapped);
            charsRef.current += 1;
            setTotalChars(charsRef.current);
            const newCI = charIndex + 1;
            setCharIndex(newCI);
            if (newCI >= currentLine.length) advanceToNextLine();
          }
          // Any wrong key in error state → do nothing
          return;
        }

        if (mapped !== expectedChar) {
          errorsRef.current += 1;
          setErrors(errorsRef.current);
          setWrongChar(true);
          setLastKeyCorrect(false);
          // Nothing appended — cursor stays on the character, shown red
          return;
        }

        setWrongChar(false);
        setLastKeyCorrect(true);
        setUserInput(prev => prev + mapped);
        charsRef.current += 1;
        setTotalChars(charsRef.current);
        const newCharIndex = charIndex + 1;
        setCharIndex(newCharIndex);
        if (newCharIndex >= currentLine.length) advanceToNextLine();
        return;
      }

      // ── SENTENCES mode (Punjabi) — existing backspace-to-fix behaviour ────
      if (wrongChar) return;

      const currentLine  = lines[lineIndex] || '';
      const expectedChar = currentLine[charIndex];

      if (mapped !== expectedChar) {
        errorsRef.current += 1;
        setErrors(errorsRef.current);
        setWrongChar(true);
        setLastKeyCorrect(false);
        setUserInput(prev => prev + mapped);
        return;
      }

      setWrongChar(false);
      setLastKeyCorrect(true);
      setUserInput(prev => prev + mapped);
      charsRef.current += 1;
      setTotalChars(charsRef.current);
      const newCharIndex = charIndex + 1;
      setCharIndex(newCharIndex);
      if (newCharIndex >= currentLine.length) advanceToNextLine();
      return;
    }

    // ── ENGLISH blocking lesson types (intro / random-words / meaningful-words) ──
    if (!isPunjabi && isBlocking) {
      if (e.key === 'Backspace') { e.preventDefault(); return; } // nothing to delete
      if (e.key.length !== 1) return; // ignore Shift, Tab, arrows, etc.
      e.preventDefault(); // we manage userInput manually

      if (linePhase !== 'visible' || isComplete) return;
      if (!startRef.current) startTimer();

      const currentLine  = lines[lineIndex] || '';
      const expectedChar = currentLine[charIndex];

      if (wrongChar) {
        // Only the correct key clears error and advances
        if (e.key === expectedChar) {
          setWrongChar(false);
          setLastKeyCorrect(true);
          setUserInput(prev => prev + e.key);
          charsRef.current += 1;
          setTotalChars(charsRef.current);
          const newCI = charIndex + 1;
          setCharIndex(newCI);
          if (newCI >= currentLine.length) advanceToNextLine();
        }
        // Wrong key in error state → do nothing
        return;
      }

      if (e.key !== expectedChar) {
        errorsRef.current += 1;
        setErrors(errorsRef.current);
        setWrongChar(true);
        setLastKeyCorrect(false);
        // Nothing typed — cursor stays, turns red
        return;
      }

      setWrongChar(false);
      setLastKeyCorrect(true);
      setUserInput(prev => prev + e.key);
      charsRef.current += 1;
      setTotalChars(charsRef.current);
      const newCI = charIndex + 1;
      setCharIndex(newCI);
      if (newCI >= currentLine.length) advanceToNextLine();
      return;
    }

    // ── ENGLISH paragraph Enter ────────────────────────────────────────────
    if (isParagraph && e.key === 'Enter') {
      e.preventDefault();
      if (linePhase !== 'visible') return;
      if (!userInput.trim()) return;
      const currentLine = lines[lineIndex] || '';
      const typed  = userInput.trim();
      const target = currentLine.replace(/\s+$/, '');
      let chunkErrors = 0;
      const maxLen = Math.max(typed.length, target.length);
      for (let i = 0; i < maxLen; i++) {
        if (typed[i] !== target[i]) chunkErrors++;
      }
      errorsRef.current += chunkErrors;
      setErrors(errorsRef.current);
      charsRef.current += currentLine.length;
      setTotalChars(charsRef.current);
      advanceToNextLine();
    }
  };

  // ─── Render current line/chunk ────────────────────────────
  const renderLine = () => {
    const line = lines[lineIndex] || '';
    const isParagraph = lessonData?.lesson?.lessonType === 'paragraph';

    if (isParagraph) {
      return (
        <>
          {line}
          <span className="enter-hint">↵</span>
        </>
      );
    }

    return line.split('').map((char, i) => {
      let cls = '';
      if (i < charIndex)        cls = 'correct';
      else if (i === charIndex) cls = wrongChar ? 'incorrect' : 'current';
      return <span key={i} className={cls}>{char}</span>;
    });
  };

  const getCurrentKey = () => {
    if (isComplete || !lines[lineIndex]) return null;
    return lines[lineIndex][charIndex] || null;
  };

  // ─── Loading / Error ──────────────────────────────────────
  if (loading) return <div className="loading">Loading lesson...</div>;
  if (error || !lessonData) return (
    <div className="container">
      <div className="error">{error || 'Lesson not found'}</div>
      <button className="btn btn-primary" onClick={() => navigate('/learn')}>Back to Lessons</button>
    </div>
  );

  const { chapter, lesson } = lessonData;
  const showKeyboard = lesson.lessonType !== 'paragraph';
  const liveAccuracy = totalChars > 0 ? Math.round(((totalChars - errors) / totalChars) * 100) : 100;
  const progressPct  = lines.length > 0 ? Math.round((lineIndex / lines.length) * 100) : 0;

  const resultElapsed = timeElapsed;
  const resultWpm = (() => {
    const mins = resultElapsed / 60 || 0.1;
    return Math.round((charsRef.current / 5) / mins);
  })();
  const resultAccuracy = lines.length > 0
    ? Math.max(0, Math.round(((lines.join(' ').length - errorsRef.current) / lines.join(' ').length) * 100))
    : 100;

  return (
    <div className="lesson-container-with-panel">
      <div className="lesson-main-area">

        {/* ── Header ── */}
        <div className="lesson-header-compact">
          <h3>Chapter {chapter.chapterNumber} • Lesson {lesson.lessonNumber}</h3>
          <span className="header-divider">|</span>
          <p>{lesson.lessonTitle}</p>
        </div>

        {/* ── Progress Bar ── */}
        <div className="line-progress-bar">
          <div className="line-progress-fill" style={{ width: `${progressPct}%` }} />
          <span className="line-counter-inline">Line {lineIndex + 1}/{lines.length}</span>
        </div>

        {/* ── Target Text (one line at a time) ── */}
        <div
          className={`typing-content line-${linePhase}`}
          style={language === 'punjabi' ? { fontFamily: "'Raavi','Noto Sans Gurmukhi',sans-serif" } : undefined}
        >
          {renderLine()}
        </div>

        {/* ── Typing Input ── */}
        {!isComplete && (
          <textarea
            ref={inputRef}
            className="typing-input"
            value={userInput}
            onChange={handleInputChange}
            onKeyDown={handleKeyDown}
            placeholder={lesson.lessonType === 'paragraph' ? "Type here… press Enter ↵ when done" : "Start typing..."}
            autoComplete="off"
            autoCorrect="off"
            autoCapitalize="off"
            spellCheck="false"
            autoFocus
            style={language === 'punjabi' ? {
              fontFamily: "'Raavi','Noto Sans Gurmukhi',sans-serif",
              fontSize: '2rem',
            } : undefined}
          />
        )}

        {/* ── Virtual Keyboard ── */}
        {showKeyboard && !isComplete && (
          <VirtualKeyboard
            activeKey={getCurrentKey()}
            isCorrect={lastKeyCorrect}
            targetKeys={lesson.targetKeys || []}
          />
        )}
      </div>

      {/* ── Right Control Panel ── */}
      {!isComplete && (
        <div className="control-panel-right">
          <div className="control-stat">
            <div className="stat-label">⏱️ TIMER</div>
            <div className="stat-value-large timer-color">{timeElapsed}s</div>
          </div>
          <div className="control-stat">
            <div className="stat-label">✓ ACCURACY</div>
            <div className="stat-value-large accuracy-color">{liveAccuracy}%</div>
          </div>
          <div className="control-stat">
            <div className="stat-label">❌ ERRORS</div>
            <div className="stat-value-large error-color">{errors}</div>
          </div>
          <div className="control-stat">
            <div className="stat-label">⚡ WPM</div>
            <div className="stat-value-large wpm-color">{calcWpm()}</div>
          </div>
          <div className="control-buttons">
            <button className="btn-control btn-submit" onClick={handleSubmit}>Submit</button>
            <button className="btn-control btn-exit" onClick={() => navigate('/learn')}>Exit</button>
          </div>
        </div>
      )}

      {/* ── Results Modal ── */}
      {showResults && (
        <div className="results-modal">
          <div className="results-content">
            <h2>Lesson Complete! 🎉</h2>
            <div className="results-stats">
              <div className="result-stat"><h3>{resultWpm}</h3><p>Words Per Minute</p></div>
              <div className="result-stat"><h3>{resultAccuracy}%</h3><p>Accuracy</p></div>
              <div className="result-stat"><h3>{resultElapsed}s</h3><p>Time Taken</p></div>
              <div className="result-stat"><h3>{errorsRef.current}</h3><p>Errors</p></div>
            </div>
            <div className="results-actions">
              <button className="btn btn-primary" onClick={() => navigate('/learn')}>Back to Lessons</button>
              <button className="btn btn-secondary" onClick={() => window.location.reload()}>Try Again</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default Lesson;
